const lead = $input.first().json;
let score = 50; // base

// Contact quality
if (lead.phone) score += 30;
if (lead.email && lead.email.includes('@')) score += 20;

// Stage progression
const stageWeights = { new: 0, contacted: 1, trial: 2 };
const stageValue = stageWeights[lead.stage] || 0;
if (stageValue >= 2) score += 30;  // reached trial
else if (stageValue >= 1) score += 10; // at least contacted

// Days in stage penalty
const days = lead.days_in_stage || 0;
if (days >= 10) score -= 40;
else if (days >= 5) score -= 20;

// Recency bonus (updated recently = interacted)
const daysSinceUpdate = Math.floor(
  (Date.now() - new Date(lead.updated_at).getTime()) / (1000*60*60*24)
);
if (daysSinceUpdate <= 1) score += 20;
else if (daysSinceUpdate <= 3) score += 10;

score = Math.max(0, Math.min(100, score));

const label = score >= 70 ? '🔥 caliente' : score >= 40 ? '🌡️ tibio' : '❄️ frío';

return [{ json: { id: lead.id, gym_id: lead.gym_id, engagement_score: score, label, phone: lead.phone, days } }];

